/**
 * A plain string or a locale-keyed map for i18n support.
 * @example "Name"
 * @example { "en-US": "Name", "ko-KR": "이름" }
 */
export type LocalizedString = string | Record<string, string>;

export const FormFieldType = {
  TEXT: 'text',
  NUMBER: 'number',
  EMAIL: 'email',
  TEL: 'tel',
  SELECT: 'select',
  CHECKBOX: 'checkbox',
  RADIO: 'radio',
  DATE: 'date',
  TEXTAREA: 'textarea',
  FILE: 'file',
  // Display-only (non-input) fields
  HEADING: 'heading',
  PARAGRAPH: 'paragraph',
  SEPARATOR: 'separator',
} as const;

/** Field types that are display-only and do not collect form data */
export const DISPLAY_FIELD_TYPES: readonly FormFieldType[] = [
  FormFieldType.HEADING,
  FormFieldType.PARAGRAPH,
  FormFieldType.SEPARATOR,
];

export const isDisplayField = (type: FormFieldType): boolean =>
  (DISPLAY_FIELD_TYPES as readonly string[]).includes(type);

export type FormFieldType = (typeof FormFieldType)[keyof typeof FormFieldType];

export type FormFieldOption = {
  value: string;
  label: LocalizedString;
};

export type FormFieldValidation = {
  minLength?: number;
  maxLength?: number;
  min?: number;
  max?: number;
  pattern?: string;
  customRule?: string;
};

export type FormFieldConditionOperator = 'eq' | 'neq' | 'gt' | 'lt' | 'contains' | 'empty' | 'notEmpty';

export type FormFieldCondition = {
  field: string;
  operator: FormFieldConditionOperator;
  value?: unknown;
};

export type FormFieldDefinition = {
  id: string;
  type: FormFieldType;
  label: LocalizedString;
  placeholder?: LocalizedString;
  description?: LocalizedString;
  required?: boolean;
  defaultValue?: unknown;
  order: number;
  options?: FormFieldOption[];
  validation?: FormFieldValidation;
  condition?: FormFieldCondition;
};

export type FormSchemaSettings = {
  layout?: 'vertical' | 'horizontal';
  showProgressBar?: boolean;
  successMessage?: LocalizedString;
};

export type FormSchema = {
  id: string;
  title: LocalizedString;
  description?: LocalizedString;
  fields: FormFieldDefinition[];
  submitLabel?: LocalizedString;
  settings?: FormSchemaSettings;
};

import type { FormFieldDefinition, LocalizedString } from './types';

export const localizeText = (
  content: string | Record<string, string> | undefined,
  locale?: string,
  baseLocale?: string,
): string => {
  if (!content) return '';

  if (!locale) {
    if (typeof content === 'string') return content;
    if (baseLocale && content[baseLocale]) return content[baseLocale];
    return Object.values(content)[0] ?? '';
  }

  if (typeof content === 'object') {
    if (content[locale]) return content[locale];

    const localeLang = locale.split('-')[0];
    const langKey = Object.keys(content).find((k) => k === localeLang || k.startsWith(`${localeLang}-`));
    if (langKey && content[langKey]) return content[langKey];

    if (baseLocale && content[baseLocale]) return content[baseLocale];

    if (baseLocale) {
      const baseLang = baseLocale.split('-')[0];
      const baseLangKey = Object.keys(content).find((k) => k === baseLang || k.startsWith(`${baseLang}-`));
      if (baseLangKey && content[baseLangKey]) return content[baseLangKey];
    }
  }

  if (typeof content === 'string') return content;

  return Object.values(content)[0] ?? '';
};

export const localizeFormField = (
  field: FormFieldDefinition,
  locale: string,
  baseLocale?: string,
): { label: string; placeholder?: string; description?: string } => ({
  label: localizeText(field.label, locale, baseLocale),
  placeholder: field.placeholder ? localizeText(field.placeholder, locale, baseLocale) : undefined,
  description: field.description ? localizeText(field.description, locale, baseLocale) : undefined,
});

export const localizeString = (content: LocalizedString | undefined, locale: string, baseLocale?: string): string =>
  localizeText(content, locale, baseLocale);

import type { RJSFSchema, UiSchema } from '@rjsf/utils';
import type { FormFieldDefinition, FormSchema } from './types';
import { FormFieldType, isDisplayField } from './types';
import { localizeFormField, localizeString } from './i18n';

const fieldTypeToJsonSchema = (field: FormFieldDefinition, locale: string, baseLocale?: string): RJSFSchema => {
  switch (field.type) {
    case FormFieldType.NUMBER:
      return { type: 'number' };
    case FormFieldType.EMAIL:
      return { type: 'string', format: 'email' };
    case FormFieldType.TEL:
      return { type: 'string', format: 'tel' };
    case FormFieldType.DATE:
      return { type: 'string', format: 'date' };
    case FormFieldType.CHECKBOX:
      return { type: 'boolean' };
    case FormFieldType.SELECT:
    case FormFieldType.RADIO:
      return {
        type: 'string',
        enum: field.options?.map((o) => o.value) ?? [],
      };
    case FormFieldType.FILE:
      return { type: 'string', format: 'data-url' };
    case FormFieldType.TEXT:
    case FormFieldType.TEXTAREA:
    default:
      return { type: 'string' };
  }
};

const applyValidation = (schema: RJSFSchema, field: FormFieldDefinition): RJSFSchema => {
  if (!field.validation) return schema;

  const result: RJSFSchema = { ...schema };
  const { minLength, maxLength, min, max, pattern } = field.validation;

  if (minLength !== undefined) result.minLength = minLength;
  if (maxLength !== undefined) result.maxLength = maxLength;
  if (min !== undefined) result.minimum = min;
  if (max !== undefined) result.maximum = max;
  if (pattern !== undefined) result.pattern = pattern;

  return result;
};

export const toJsonSchema = (formSchema: FormSchema, locale: string, baseLocale?: string): RJSFSchema => {
  const properties: Record<string, RJSFSchema> = {};
  const required: string[] = [];

  const sortedFields = [...formSchema.fields].sort((a, b) => a.order - b.order);

  for (const field of sortedFields) {
    // Display fields use a null-type schema placeholder (rendered via custom UI field)
    if (isDisplayField(field.type)) {
      const localized = localizeFormField(field, locale, baseLocale);
      properties[field.id] = {
        type: 'null',
        title: localized.label,
        description: localized.description,
      };
      continue;
    }

    const localized = localizeFormField(field, locale, baseLocale);
    const typeSchema = fieldTypeToJsonSchema(field, locale, baseLocale);

    let fieldSchema: RJSFSchema = {
      ...typeSchema,
      title: localized.label,
    };

    if (localized.description) {
      fieldSchema.description = localized.description;
    }

    if (field.defaultValue !== undefined) {
      fieldSchema.default = field.defaultValue as string | number | boolean;
    }

    fieldSchema = applyValidation(fieldSchema, field);
    properties[field.id] = fieldSchema;

    if (field.required) {
      required.push(field.id);
    }
  }

  const schema: RJSFSchema = {
    type: 'object',
    title: localizeString(formSchema.title, locale, baseLocale),
    properties,
  };

  if (formSchema.description) {
    schema.description = localizeString(formSchema.description, locale, baseLocale);
  }

  if (required.length > 0) {
    schema.required = required;
  }

  return applyConditions(schema, sortedFields);
};

export const toUiSchema = (formSchema: FormSchema, locale: string, baseLocale?: string): UiSchema => {
  const uiSchema: UiSchema = {};
  const sortedFields = [...formSchema.fields].sort((a, b) => a.order - b.order);

  uiSchema['ui:order'] = sortedFields.map((f) => f.id);

  for (const field of sortedFields) {
    const localized = localizeFormField(field, locale, baseLocale);
    const fieldUi: UiSchema = {};

    if (localized.placeholder) {
      fieldUi['ui:placeholder'] = localized.placeholder;
    }

    // Move enumNames to uiSchema (deprecated in JSON Schema)
    if ((field.type === FormFieldType.SELECT || field.type === FormFieldType.RADIO) && field.options?.length) {
      fieldUi['ui:enumNames'] = field.options.map((o) => localizeString(o.label, locale, baseLocale));
    }

    switch (field.type) {
      case FormFieldType.TEXTAREA:
        fieldUi['ui:widget'] = 'textarea';
        break;
      case FormFieldType.RADIO:
        fieldUi['ui:widget'] = 'radio';
        break;
      case FormFieldType.FILE:
        fieldUi['ui:widget'] = 'file';
        break;
      case FormFieldType.HEADING:
        fieldUi['ui:field'] = 'HeadingField';
        break;
      case FormFieldType.PARAGRAPH:
        fieldUi['ui:field'] = 'ParagraphField';
        break;
      case FormFieldType.SEPARATOR:
        fieldUi['ui:field'] = 'SeparatorField';
        break;
    }

    if (Object.keys(fieldUi).length > 0) {
      uiSchema[field.id] = fieldUi;
    }
  }

  if (formSchema.settings?.layout === 'horizontal') {
    uiSchema['ui:rootFieldId'] = 'root';
    uiSchema['classNames'] = 'form-horizontal';
  }

  return uiSchema;
};

/**
 * Evaluates a single field condition against current form data.
 * Used by FormRenderer to filter visible fields before building the JSON schema.
 */
export const evaluateCondition = (
  condition: FormFieldDefinition['condition'],
  formData: Record<string, unknown>,
): boolean => {
  if (!condition) return true;
  const value = formData[condition.field];
  switch (condition.operator) {
    case 'eq':       return value === condition.value;
    case 'neq':      return value !== condition.value;
    case 'gt':       return typeof value === 'number' && value > (condition.value as number);
    case 'lt':       return typeof value === 'number' && value < (condition.value as number);
    case 'contains': return typeof value === 'string' && value.includes(String(condition.value));
    case 'empty':    return value === undefined || value === null || value === '';
    case 'notEmpty': return value !== undefined && value !== null && value !== '';
    default:         return true;
  }
};

export const applyConditions = (schema: RJSFSchema, fields: FormFieldDefinition[]): RJSFSchema => {
  const fieldsWithConditions = fields.filter((f) => f.condition);
  if (fieldsWithConditions.length === 0) return schema;

  const allOf: RJSFSchema[] = [];

  for (const field of fieldsWithConditions) {
    const { condition } = field;
    if (!condition) continue;

    let ifSchema: RJSFSchema;

    switch (condition.operator) {
      case 'eq':
        ifSchema = { properties: { [condition.field]: { const: condition.value as string | number | boolean } } };
        break;
      case 'neq':
        ifSchema = {
          properties: { [condition.field]: { not: { const: condition.value as string | number | boolean } } },
        };
        break;
      case 'gt':
        ifSchema = {
          properties: { [condition.field]: { exclusiveMinimum: condition.value as number } },
        };
        break;
      case 'lt':
        ifSchema = {
          properties: { [condition.field]: { exclusiveMaximum: condition.value as number } },
        };
        break;
      case 'contains':
        ifSchema = {
          properties: { [condition.field]: { pattern: String(condition.value) } },
        };
        break;
      case 'empty':
        ifSchema = {
          properties: { [condition.field]: { maxLength: 0 } },
        };
        break;
      case 'notEmpty':
        ifSchema = {
          properties: { [condition.field]: { minLength: 1 } },
        };
        break;
      default:
        continue;
    }

    allOf.push({
      if: ifSchema,
      then: { properties: { [field.id]: schema.properties?.[field.id] as RJSFSchema } },
      else: {},
    });
  }

  if (allOf.length > 0) {
    return { ...schema, allOf };
  }

  return schema;
};

import type { CustomValidator, FormValidation } from '@rjsf/utils';
import type { FormSchema } from './types';

type ValidatorFn = (value: unknown, formData: Record<string, unknown>) => string | undefined;

const customValidators = new Map<string, ValidatorFn>();

export const registerValidator = (key: string, fn: ValidatorFn): void => {
  customValidators.set(key, fn);
};

export const unregisterValidator = (key: string): void => {
  customValidators.delete(key);
};

export const createCustomValidator = (formSchema: FormSchema): CustomValidator => {
  return (formData: Record<string, unknown>, errors: FormValidation) => {
    for (const field of formSchema.fields) {
      const customRule = field.validation?.customRule;
      if (!customRule) continue;

      const validator = customValidators.get(customRule);
      if (!validator) continue;

      const value = formData[field.id];
      const error = validator(value, formData);

      if (error) {
        (errors as any)[field.id]?.addError(error);
      }
    }

    return errors;
  };
};
